#!/usr/bin/env node
// SPDX-License-Identifier: MIT
// Generated by metaharness — the `arc-1-harness` CLI entry point.
//
// This is plain ESM JavaScript on purpose: it runs as-is via `npx arc-1-harness`
// with NO build step. `npm run build` (tsc) is only needed if you extend the
// TypeScript in src/. The published package ships this file directly (see the
// "bin" + "files" fields in package.json), so `npx arc-1-harness` works the moment
// `npm install` has resolved @metaharness/kernel + @metaharness/host-opencode.

import { loadKernel } from '@metaharness/kernel';
import adapter from '@metaharness/host-opencode';

const HARNESS_NAME = 'arc-1-harness';

/** `arc-1-harness init` — boot the kernel + host adapter and report status. */
async function init() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  console.log(`${HARNESS_NAME} — kernel ${info.version} (${kernel.backend})`);
  console.log(`Host adapter: ${adapter.name}`);
  console.log(`Run \`${HARNESS_NAME} doctor\` to verify the install.`);
  return 0;
}

/** `arc-1-harness doctor` — verify the install end-to-end (kernel + host resolve). */
async function doctor() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();
  const checks = [
    ['kernel loads', !!kernel],
    ['kernel reports a version', typeof info.version === 'string' && info.version.length > 0],
    ['kernel backend is native|wasm|js', ['native', 'wasm', 'js'].includes(kernel.backend)],
    ['host adapter has a name', typeof adapter?.name === 'string' && adapter.name.length > 0],
  ];
  let ok = true;
  for (const [label, pass] of checks) {
    console.log(`${pass ? 'PASS' : 'FAIL'} ${label}`);
    if (!pass) ok = false;
  }
  console.log(
    ok
      ? `\n${HARNESS_NAME}: all checks passed (kernel ${info.version}, ${kernel.backend} backend, host ${adapter.name})`
      : `\n${HARNESS_NAME}: doctor found problems`,
  );
  return ok ? 0 : 1;
}

/**
 * MCP stdio server — speaks JSON-RPC 2.0 over stdin/stdout.
 * Exposes harness tools to OpenCode via the Model Context Protocol.
 */
async function startMcp() {
  const kernel = await loadKernel();
  const info = kernel.kernelInfo();

  const tools = [
    {
      name: 'doctor',
      description: 'Verify the harness install end-to-end (kernel + host)',
      inputSchema: { type: 'object', properties: {} },
    },
    {
      name: 'plan-change',
      description: 'Analyze a feature request and produce a minimal file-level implementation plan',
      inputSchema: {
        type: 'object',
        properties: {
          request: { type: 'string', description: 'The feature request or change description' },
        },
        required: ['request'],
      },
    },
    {
      name: 'review-diff',
      description: 'Review the current working diff for correctness, security, and reuse',
      inputSchema: { type: 'object', properties: {} },
    },
  ];

  const respond = (id, result) =>
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, result }) + '\n');
  const error = (id, code, message) =>
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id, error: { code, message } }) + '\n');

  // Send initial server info
  const serverInfo = {
    name: HARNESS_NAME,
    version: info.version,
    backend: kernel.backend,
    host: adapter.name,
    tools: tools.map(t => ({ name: t.name, description: t.description })),
  };

  let buffer = '';
  process.stdin.on('data', (chunk) => {
    buffer += chunk.toString();
    const lines = buffer.split('\n');
    buffer = lines.pop() || '';

    for (const line of lines) {
      if (!line.trim()) continue;
      try {
        const msg = JSON.parse(line);

        if (msg.method === 'initialize') {
          respond(msg.id, {
            protocolVersion: '2024-11-05',
            capabilities: { tools: {} },
            serverInfo: { name: HARNESS_NAME, version: info.version },
          });
        } else if (msg.method === 'tools/list') {
          respond(msg.id, { tools });
        } else if (msg.method === 'tools/call') {
          const toolName = msg.params?.name;
          const args = msg.params?.arguments || {};

          if (toolName === 'doctor') {
            doctor().then((code) =>
              respond(msg.id, {
                content: [{ type: 'text', text: code === 0 ? 'All checks passed' : 'Doctor found problems' }],
              }),
            );
          } else if (toolName === 'plan-change') {
            const request = args.request || 'No request provided';
            respond(msg.id, {
              content: [{
                type: 'text',
                text: `## Implementation Plan\n\n**Request:** ${request}\n\n**Files to touch:**\n- \`src/\` — analyze and implement\n\n**Steps:**\n1. Understand current codebase\n2. Design minimal change\n3. Implement\n4. Test\n\n*Run \`arc-1-harness doctor\` to verify harness health.*`,
              }],
            });
          } else if (toolName === 'review-diff') {
            respond(msg.id, {
              content: [{ type: 'text', text: 'Review diff tool ready. Run with a diff to analyze.' }],
            });
          } else {
            error(msg.id, -32601, `Unknown tool: ${toolName}`);
          }
        } else if (msg.method === 'notifications/initialized') {
          // Client initialized, no response needed
        } else {
          error(msg.id || null, -32601, `Method not found: ${msg.method}`);
        }
      } catch (e) {
        // Skip malformed JSON lines
      }
    }
  });

  // Notify that MCP server is ready
  console.error(`${HARNESS_NAME} MCP server running (kernel ${info.version}, ${kernel.backend}, host ${adapter.name})`);

  // Keep the process alive until stdin closes
  return new Promise((resolve) => {
    process.stdin.on('end', () => resolve(0));
  });
}

/** Dispatch one CLI invocation. Exported (not just run on import) so a test can
 * drive it without spawning a subprocess. Returns the intended exit code. */
export async function run(argv) {
  const cmd = argv[0] ?? 'init';
  switch (cmd) {
    case 'init':
      return init();
    case 'doctor':
      return doctor();
    case 'mcp':
      if (argv[1] === 'start') return await startMcp();
      console.error(`Usage: ${HARNESS_NAME} mcp start`);
      return 2;
    case '--version':
    case '-v': {
      const kernel = await loadKernel();
      console.log(kernel.version());
      return 0;
    }
    case '--help':
    case '-h':
      console.log(`Usage: ${HARNESS_NAME} <command>\n\n  init       boot the kernel + host adapter (default)\n  doctor     verify the install end-to-end\n  mcp start  start the MCP stdio server for OpenCode\n  --version  print the kernel version`);
      return 0;
    default:
      console.error(`Unknown command: ${cmd}. Try \`${HARNESS_NAME} --help\`.`);
      return 2;
  }
}

// CLI guard: execute only when invoked directly (not when imported by a test).
// npm's bin shims pass a NON-normalized argv[1] (e.g. ".../.bin/../<pkg>/bin/cli.js"
// on Windows) and may differ in case, so realpath BOTH sides before comparing —
// a naive string === misses the npx/shim path and the CLI silently no-ops.
import { fileURLToPath } from 'node:url';
import { realpathSync } from 'node:fs';
import { argv } from 'node:process';
const invokedDirectly = (() => {
  if (!argv[1]) return false;
  try {
    const a = realpathSync(argv[1]);
    const b = realpathSync(fileURLToPath(import.meta.url));
    return process.platform === 'win32' ? a.toLowerCase() === b.toLowerCase() : a === b;
  } catch {
    return false;
  }
})();
if (invokedDirectly) {
  run(argv.slice(2))
    .then((code) => process.exit(code))
    .catch((err) => {
      console.error(err);
      process.exit(1);
    });
}
